# range(5) gives 0, 1, 2, 3, 4
for i in range(5):
    print(i)

# range(1, 6) gives 1, 2, 3, 4, 5
for num in range(1, 6):
    print(num)

word = 'PyPath'
for letter in word:
    print(letter)

for i in range(10):
    if i == 3:
        continue
    if i == 7:
        break
    print(i)

for i in range(3):
    print(i)
else:
    print('Loop finished without break!')

print('---')

